"""Экспорт в XLSX: один эксперимент, серия, сессия."""from __future__ import annotationsfrom pathlib import Pathfrom typing import Any, Iterablefrom openpyxl import Workbookfrom ..core.types import ExperimentResult, ExperimentSeriesfrom ._provenance import filter_params, noise_params, signal_params_XLSX_ROW_LIMIT = 1_048_576# ----------------------- один результат --------------------------------------def export_single_xlsx(result: ExperimentResult, path: str | Path) -> Path:    path = Path(path)    wb = Workbook()    ws = wb.active    ws.title = "Parameters"    ws.append(["Раздел", "Параметр", "Значение"])    ws.append(["Общее", "timestamp", result.timestamp])    ws.append(["Общее", "signal_name", result.signal_name])    ws.append(["Общее", "noise_name", result.noise_name])    ws.append(["Общее", "filter_name", result.filter_name])    ws.append(["Общее", "trial_index", result.trial_index + 1])    ws.append(["Общее", "seed", result.seed])    for k, v in signal_params(result).items():        ws.append(["Сигнал", k, _to_cell(v)])    for k, v in noise_params(result).items():        ws.append(["Шум", k, _to_cell(v)])    for k, v in filter_params(result).items():        ws.append(["Фильтр", k, _to_cell(v)])    _widen(ws, [14, 26, 40])    wm = wb.create_sheet("Metrics")    wm.append(["Метрика", "Значение"])    m = result.metrics    wm.append(["MSE", m.mse])    wm.append(["RMSE", m.rmse])    wm.append(["SNR до, дБ", m.snr_before_db])    wm.append(["SNR после, дБ", m.snr_after_db])    wm.append(["Улучшение SNR, дБ", m.snr_improvement_db])    wm.append(["Корреляция", m.correlation])    _widen(wm, [22, 18])    ws_sig = wb.create_sheet("Signals")    ws_sig.append(["t", "clean", "noisy", "restored"])    n = result.clean.x.size    if n + 1 >= _XLSX_ROW_LIMIT:        ws_sig.append([f"(N={n} превышает лимит Excel, сырые данные пропущены)",                       "", "", ""])    else:        t = result.clean.t        c = result.clean.x        no = result.noisy.x        r = result.restored.x        for i in range(n):            ws_sig.append([float(t[i]), float(c[i]), float(no[i]), float(r[i])])    wb.save(path)    return path# ----------------------- серия -----------------------------------------------_RUN_HEADERS = [    "timestamp", "signal_name", "noise_name", "filter_name",    "trial_index", "seed",    "mse", "rmse",    "snr_before_db", "snr_after_db", "snr_improvement_db", "correlation",]_AGG_HEADERS = [    "filter_name", "n_trials",    "mse_mean", "mse_std",    "rmse_mean", "rmse_std",    "snr_before_db_mean", "snr_before_db_std",    "snr_after_db_mean", "snr_after_db_std",    "snr_improvement_db_mean", "snr_improvement_db_std",    "correlation_mean", "correlation_std",]def export_series_xlsx(series: ExperimentSeries, path: str | Path) -> Path:    path = Path(path)    wb = Workbook()    ws = wb.active    ws.title = "Runs"    ws.append(_RUN_HEADERS)    for _fname, _i, r in series.iter_results():        m = r.metrics        ws.append([            r.timestamp, r.signal_name, r.noise_name, r.filter_name,            r.trial_index + 1, r.seed,            float(m.mse), float(m.rmse),            float(m.snr_before_db), float(m.snr_after_db),            float(m.snr_improvement_db), float(m.correlation),        ])    _widen(ws, [22, 28, 22, 28, 12, 12, 14, 14, 14, 14, 16, 14])    wa = wb.create_sheet("Aggregate")    wa.append(_AGG_HEADERS)    for fname in series.filter_names:        a = series.aggregates[fname]        wa.append([            a.filter_name, a.n_trials,            float(a.mse_mean), float(a.mse_std),            float(a.rmse_mean), float(a.rmse_std),            float(a.snr_before_db_mean), float(a.snr_before_db_std),            float(a.snr_after_db_mean), float(a.snr_after_db_std),            float(a.snr_improvement_db_mean), float(a.snr_improvement_db_std),            float(a.correlation_mean), float(a.correlation_std),        ])    _widen(wa, [28, 10, *[14] * 12])    wb.save(path)    return path# ----------------------- сессия ---------------------------------------------def export_session_xlsx(entries: Iterable[Any], path: str | Path) -> Path:    """    Совместимость + расширение. `entries` может содержать:      * ExperimentResult — записывается одной строкой;      * ExperimentSeries — разворачивается в строки всех результатов.    """    path = Path(path)    wb = Workbook()    ws = wb.active    ws.title = "Summary"    ws.append(_RUN_HEADERS)    for entry in entries:        if isinstance(entry, ExperimentSeries):            for _f, _i, r in entry.iter_results():                ws.append(_row_from_result(r))        elif isinstance(entry, ExperimentResult):            ws.append(_row_from_result(entry))        # другие типы — игнорируем    _widen(ws, [22, 28, 22, 28, 12, 12, 14, 14, 14, 14, 16, 14])    wb.save(path)    return path# ----------------------- утилиты --------------------------------------------def _row_from_result(r: ExperimentResult) -> list:    m = r.metrics    return [        r.timestamp, r.signal_name, r.noise_name, r.filter_name,        r.trial_index + 1, r.seed,        float(m.mse), float(m.rmse),        float(m.snr_before_db), float(m.snr_after_db),        float(m.snr_improvement_db), float(m.correlation),    ]def _to_cell(v: Any) -> Any:    if isinstance(v, (int, float, str, bool)) or v is None:        return v    return str(v)def _widen(ws, widths: list[int]) -> None:    for i, w in enumerate(widths, start=1):        col = ws.cell(row=1, column=i).column_letter        ws.column_dimensions[col].width = w